var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어휴...... 마지막 등교날까지 침식체나 상대하고 이게 무슨 난리야.","JPN":"ふう……なんてこった。\\n最後の登校日なのに侵食体なんかを相手にすることになるなんて。","ENG":"Gah! I can't believe I fought C.O. on my last day at school.","TWN":"哈……最後一天上學還要跟侵蝕體戰鬥，這也太衰了吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"후훗. 그래도 의외네.","JPN":"ふふっ。でも意外だったよ。","ENG":"Hah hah. But that was surprising.","TWN":"呵呵...真是個意外啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"엄청 거칠게 싸우면서도 고양이는 제대로 안 놓치던걸?","JPN":"あれだけ激しく戦ってても、絶対に猫を離さなかったでしょう？","ENG":"You didn't let go of the cat even as you fought tooth and nail.","TWN":"要是戰鬥再激烈一點，它們連貓也不會放過的吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"거, 거기서 놓쳐 버리면 괜히 다칠지도 모르잖아!","JPN":"あ、あそこで離したら怪我するかもしれないだろ！","ENG":"I-I didn't want him to get hurt!","TWN":"那，那要是它們在哪裡遇上的話,貓會平白無故受傷的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"응, 응. 네 맘 알아. 원래 귀여운 동물은 보호본능을 자극한다잖아.","JPN":"うんうん、わかるよ。可愛い動物は庇護欲を刺激するって言うよね。","ENG":"Sure, sure. I understand. Cute animals stimulate our protective instinct.","TWN":"嗯...我懂了，原來可愛的動物會激發妳的保護欲啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"거기 태평하게 교문으로 들어오고 있는 둘, 그대로 멈춰라.","JPN":"そこ、のんきに校門から入ってきている二人。そのまま止まれ。","ENG":"You two, sauntering toward the gate as if you've got all the time in the world. Halt.","TWN":"喂，那邊，就是妳們！在那邊悠哉走進校門的兩個人，停下來。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SNAP"},{"id":"L10_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭐야? 오늘도 지각한 사람 잡는 거였어?","JPN":"なんだ？　今日も遅刻したやつを捕まえるのか？","ENG":"Are you serious? You're going to catch us for tardiness, on our last day at school?","TWN":"這是幹嘛？今天在抓遲到的人嗎?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"당연하지. 예외를 받아 주기 시작하면 규율이 허물어진다.","JPN":"当然だ。例外を認めてしまうと規律が崩れる。","ENG":"Absolutely. Making an exception is breaking the rules.","TWN":"當然，如果開始姑息例外，整個學校的紀律都會被打亂的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그리고 이 시간이 돼서야 등교하다니, 이건 명백한 지각이다.","JPN":"それに、今さら登校するとはな。これは明らかな遅刻だ。","ENG":"And last day or not, you're obviously late to school.","TWN":"再說，在這個時間才進校門，分明就是遲到。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"안녕, 선도부장~ 좋은 아침!","JPN":"やあ、風紀委員長～おはよう！","ENG":"Hey, Student Guide Leader. Good morning!","TWN":"先鋒部隊長~早上好！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"하늘은 봤어? 오늘 하늘이 정말 푸르지 않니?","JPN":"空は見た？　本当に青くない？","ENG":"Did you see the sky? It's so blue and beautiful today, isn't it?","TWN":"妳看到天空了嗎？今天的天空很藍耶！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그러고 보니...... 이렇게 푸른 하늘은 오랜만이군.","JPN":"そういえば……こんなに青い空は久しぶりだな。","ENG":"Now that you mention it... I haven't seen such a blue sky for a long time.","TWN":"這樣說來...這麼藍的天空也是很久沒看到了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"한동안 침식파 때문에 밤낮으로 칙칙한 잿빛만 펼쳐져 있었는데......","JPN":"しばらく侵食波のせいで、一日中くすんだ灰色だけが広がっていたのに……","ENG":"Lately, it's been gray all day because of the Corruption rays...","TWN":"這段時間由於受侵蝕波的影響，不論日夜，天空就只有昏暗的灰白色……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"아니, 감상에 빠져 있을 때가 아니지.","JPN":"いや、感傷にふけっている場合じゃない。","ENG":"No, what am I talking about?","TWN":"不，現在不是沉浸在感傷中的時候。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"말 돌리지 마라. 얼렁뚱땅 넘어가려고 해도 소용없다.","JPN":"話を逸らすな。うやむやにしてごまかそうとしても無駄だぞ。","ENG":"Don't try to distract me. It doesn't work on me.","TWN":"別給我扯開話題！妳想瞞混過關也沒用。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"특히 서윤, 그대는 반장으로서 타의 모범이 되여야 할 입장임에도 각오가 부족하군.","JPN":"特にアオイ・シズカ。\\n君は学級委員長として他の模範になるべき立場なのに、覚悟が足りないな。","ENG":"Especially you, Seo Yoon. As a class president, you're not setting a good example for your classmates.","TWN":"特別是妳，徐芸！作為班長應該要做別人的榜樣，但是妳卻沒這個認知。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"교정에서의 마지막 날인지 아닌지는 중요하지 않다. 둘 다 엄하게......","JPN":"校舎での最後の日かどうかは重要じゃない。二人とも厳しく……","ENG":"It doesn't matter whether or not this is your last day at school. Both of you must be strictly—","TWN":"不管今天是不是妳們在校的最後一天，妳們兩個依舊都要嚴格地…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"앗, 고양......!","JPN":"あっ、ね……！","ENG":"Ah, Ki—","TWN":"啊！是小貓……！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"이......","JPN":"こ……","ENG":"Tty...","TWN":"欸？這……？？？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"오호라......","JPN":"ふうん……","ENG":"Ooooh...","TWN":"真的好……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"엄하게, 뭐?","JPN":"厳しく、なんだ？","ENG":"We must be strictly what?","TWN":"嚴，嚴格地...什麼？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"왜 말을 하다 말아? 선도부장답지 않게?","JPN":"なぜ話を途中でやめるんだ？　らしくないな。","ENG":"Why did you stop, Student Guide Leader? That's so not like you.","TWN":"怎麼不說話了？ 真不像是先鋒部隊長會幹的事。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"자, 잠시 당황했을 뿐이다.","JPN":"ち、ちょっと慌てただけだ。","ENG":"I-I got distracted for a moment.","TWN":"我，我只是稍微慌了一下。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그렇게 꼭 끌어안고 있다니...... 자기가 귀여운 동물과 교감할 수 있다고 전교에 과시할 셈이냐......?","JPN":"そんなにぎゅっと抱きしめるなんて……\\n自分は可愛い動物と触れ合えると全校に自慢でもする気か……？","ENG":"Holding him so tightly to your chest... Are you trying to flaunt your ability to commune with cute animals to everyone in school?","TWN":"難道妳想這樣…… 向全校炫耀自己能抱這麼可愛的動物嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"안 되겠군. 두 사람은 교칙에 의거해서, 화단 청소를......","JPN":"ダメだ。二人とも校則に従って花壇の掃除を……","ENG":"You're helpless. In accordance with the school rules, you two must clean the flowerbeds—","TWN":"絕對不允許。那麼根據校規，妳們兩個都給我去打掃花圃……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"앗, 야. 하품하지 마. 지금 잠들어 버리면 어디다 내려 놓으라고.","JPN":"あっ、おい。あくびするなよ。今寝ちゃったら置き場に困るだろうが。","ENG":"Ah, hey! Stop yawning. You can't fall asleep now. I don't know where to put you down.","TWN":"喂！別打哈欠。要是妳現在睡著了，貓要怎麼辦啊？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그나저나 이상하네. 선도부장이 아까부터 눈을 못 마주치고 있는데.","JPN":"ところで変だな。風紀委員長がさっきから目を合わせられないようだが。","ENG":"By the way, this is strange. The Student Guide Leader keeps turning her eyes away from me.","TWN":"不過真奇怪，先鋒部隊長從剛才表情就很僵硬。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"반장, 혹시 예전에 선도부장이 저러던 거 본 적 있어?","JPN":"委員長、風紀委員長があんな様子だったことなんて今まであったか？","ENG":"Class President, have you seen her doing that before?","TWN":"班長啊，妳以前見過先鋒部隊長這種樣子嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아니, 나도 오늘 처음 보는데? 왜 저러는지 궁금해지지 않아?","JPN":"ううん、私も今日が初めて。なんでなのか気にならない？","ENG":"No, never. You want to know why, don't you?","TWN":"沒有，我也是今天第一次見到，我還蠻好奇她為什麼這樣呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"나는 언제나와 같다. 그저......","JPN":"私はいつもと変わらない。ただ……","ENG":"I'm the same as usual. I just...","TWN":"我和平常沒什麼不同，只是…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그저......","JPN":"ただ……","ENG":"Just...","TWN":"只是…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"고양이 알레르기가 있기 때문이다!","JPN":"猫アレルギーがあるからだ！","ENG":"I'm allergic to cats, alright?!","TWN":"因為我對貓過敏，這才…!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L41_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"고작 알레르기 고백 치곤 세상을 다 잃었다는 표정인데......","JPN":"アレルギーの告白にしては、あまりにも絶望的な顔をしてるけど……","ENG":"But you look as if the world has come to an end.","TWN":"好個對貓“過敏”，明明表情就像是失去全世界一樣。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"큭......","JPN":"クッ……","ENG":"Hmpf!","TWN":"唔..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"저기, 유진아. 나한테 좋은 생각이 있어.","JPN":"ねえ、シロコ。私にいい考えがある。","ENG":"Hey, Eujin. I've got an idea.","TWN":"啊，劉珍啊，我有個好主意。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"응? 무슨 좋은 생각?","JPN":"うん？　いい考え？","ENG":"Mm? What do you mean?","TWN":"嗯？什麼好主意？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"네가 안고 있는 고양이를 안아 보라고 하자. 우리 고고한 선도부장님이 어떻게 반응할지 궁금하지 않아?","JPN":"あなたが抱きしめている猫を抱いてみてって言うのよ。\\nうちの孤高な風紀委員長がどんな反応をするか、気にならない？","ENG":"Why don't we let her hold the cat? Don't you want to see how our high-and-mighty Student Guide Leader would respond to him?","TWN":"把妳抱著的貓去給先鋒部隊隊長抱抱，難道妳不好奇我們高冷的先鋒部隊長會有什麼反應嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"고고한 선도부장의 의외의 일면! 이건 분명 히트할 거야!","JPN":"孤高な風紀委員長の意外な一面！　これは間違いなくヒットする！","ENG":"We might even discover a completely unexpected side of her, and it's going to make this video a hit!","TWN":"孤冷的先鋒部隊隊長令人意外的一面！這一定會成為話題的"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"반장...... 촬영에 너무 푹 빠진 거 아냐?","JPN":"委員長……撮影に夢中すぎじゃないか？","ENG":"Class President. Don't you think you're too obsessed with filming?","TWN":"班長……妳…是不是太沉迷攝影了？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭐, 나야 누가 이 녀석을 대신 맡아 주겠다고 하면 고맙지.","JPN":"まぁ、俺としてはこいつを代わりに預かってくれたらありがたいけど。","ENG":"Well, I'll be grateful if anyone can take him off my hands.","TWN":"不過，要是有人能代替我被拍，那當然再好不過了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어쩔래, 에스텔? 알레르기는 아닌 거 같은데 한 번 안아 볼래?","JPN":"どうだ、エステル？　アレルギーではなさそうだし、一度抱いてみないか？","ENG":"What do you think, Esther? I don't think you're allergic to cats. Want to try to hold him?","TWN":"怎麼樣，艾斯特洛索？ 這不會過敏的，妳要不要抱抱它？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"나는...... 나는 선도부원들과 약속했다......","JPN":"私は……私は風紀委員たちと約束した……","ENG":"I... I've made a promise to the other members of the Council...","TWN":"我…我和先鋒部隊成員約好了要…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그 무엇에도 꺾이지 않는...... 최강의 선도부장이 되기로!","JPN":"どんなものにも屈しない……最強の風紀委員長になると！","ENG":"that I'll be the strongest leader that they've ever had, who can't be swayed by anything!","TWN":"一向所向無敵…… 身為最強先鋒部隊長的我！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그런 내가 고작 고양이 따위에 동요할 것 같은가?","JPN":"そんな私が、たかが猫に動揺すると思うか？","ENG":"Do you really think a mere cat can sway me?","TWN":"怎麼可能對一隻貓就動搖呢？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"자~ 잠깐 만져만 보라니까?","JPN":"ほら～ちょっとだけ触ってみろよ。","ENG":"Come on, just pet him.","TWN":"來～那就摸一下吧？只摸一下！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"큭, 연약한 동물을 이용해서 단죄를 모면하려 하다니, 어찌 이리도 비열할 수가......!","JPN":"くっ、か弱い動物を利用して断罪を免れようとするとは、なんて卑劣なんだ……！","ENG":"Grr, I can't believe you're using such a tiny animal to avoid punishment. You're so cunning!","TWN":"哼，這兩個傢夥想要利用這隻柔軟的小動物躲避懲罰，這未免太狡猾…！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"미안하다, 피오네. 나는 더 이상...... 저 말랑말랑한 육구에서 헤어나올 수 없게 된 것 같아......","JPN":"すまない、フィオネ。\\n私はもう……あの柔らかい肉球から抜け出せなくなってしまった……","ENG":"I'm sorry, Fione. I can't... I can't resist his soft, pink pads anymore...","TWN":"對不起，菲奧尼。我好像已經…沒有辦法從這軟綿綿的肉球中脫身了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"응? 이 녀석, 얌전하다가 왜 갑자기 안절부절하고 그래?","JPN":"あれ？　こいつ、大人しかったのにいきなりそわそわし始めたぞ？","ENG":"Mm? Why is he anxious all of a sudden?","TWN":"嗯？你這小毛球， 不是一直很乖嗎，怎麼突然這麼不安分呢?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"서, 설마 그렇게까지 완강하게 거부할 만큼 내 손길이 싫단 뜻인가......!","JPN":"ま、まさか。そこまで強く拒否するほど私の手が触れるのが嫌だということか……！","ENG":"D-does he hate my touch so much that he's acting violent?","TWN":"沒…沒想到會反抗得這麼激烈，難道牠很討厭我嗎…！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"선도부장이 싫어서 그런 건 아닌가 본데.","JPN":"風紀委員長が嫌いだからじゃないと思うよ。","ENG":"I don't think he's doing it because he hates you.","TWN":"牠似乎不是因為討厭先鋒部隊長才這樣的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"등굣길에 침식체를 피해서 도망쳐 온 걸 주운 거거든.","JPN":"実はこの子、登校中に侵食体から逃げてきたのを拾ったの。","ENG":"He was running from C.O. when we picked him up on our way to school.","TWN":"牠是為了躲避侵蝕體才逃到這裡，結果剛好被上學路上的我們撿到。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"침식체들 때문에 무서워하는 것 같아. 아마 아카데미 근처에도 어슬렁거린다는 거겠지.","JPN":"侵食体のせいで怖がってるみたい。まだアカデミーの近くをうろついてるってことでしょうね。","ENG":"I think he's afraid of C.O., which means they're nearby.","TWN":"大概是侵蝕體還在學校附近徘徊吧，所以牠才會這麼害怕。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그런가......","JPN":"そういうことか……","ENG":"I see...","TWN":"是嗎……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"무도한 놈들, 이 교정에서 마지막으로 보내는 뜻 깊은 날까지 훼방 놓을 작정이군.","JPN":"非道なやつらだ。この校舎での最後の日まで邪魔するつもりだな。","ENG":"Those mindless monsters are determined to ruin our last day at school.","TWN":"唉，那些毫無人性的侵蝕體，連我們在校園度過的最後幾天都想要毀掉。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"좋다. 외부자의 전횡을 막는 것도 선도부의 소임.","JPN":"いいだろう。外部の者の専横を防ぐことも風紀委員会の役目。","ENG":"Alright, it's also us Student Guides' duty to keep intruders away from school.","TWN":"好，防止外人在這裡橫行也是我們先鋒部隊的職責。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"유진, 그리고 반장. 지각에 대한 처벌은 보류하겠다. 전투에 휘말리지 않게 피해 있어라.","JPN":"シロコ、そして委員長。遅刻の処罰は保留とする。\\n戦闘に巻き込まれないよう下がっていろ。","ENG":"Eujin, and Class President. For now, I'm postponing your punishment for tardiness. Stay away from the battle scene.","TWN":"劉珍，還有班長，我暫且保留妳們兩個遲到的處罰，我要妳們先去避開這場戰鬥。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"기어코 화단 청소는 시킬 작정이구만......","JPN":"何があっても花壇の掃除はやらせるつもりだな……","ENG":"She's really going to make us clean the flowerbeds.","TWN":"最後還是得去打掃花圃啊…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그럼 이건 어때, 선도부장? 침식체랑 싸우는 걸 도와 주는 대신 화단 청소는 봐 주기로.","JPN":"これならどうだ？　侵食体と戦うのを手伝う代わり、花壇の掃除は勘弁してくれ。","ENG":"How about this, Student Guide Leader? We'll help you fight the C.O. if you don't make us clean the flowerbeds.","TWN":"不然這樣吧，先鋒部隊長。我們和妳一起去和侵蝕體戰鬥，用這個來代替打掃花圃的處罰？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"확실히 너희도 아카데미의 학생다운 실력을 갖춘 카운터들이긴 하지.","JPN":"確かに、君たちもアカデミーの生徒らしい実力のあるカウンターだったな。","ENG":"You two are definitely good Counters, good enough to represent the Academy.","TWN":"確實，妳們也算是學院中具有實力的學生，和制裁者相比也..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"하지만 괜찮겠나?","JPN":"でもいいのか？","ENG":"But are you sure?","TWN":"但真的沒問題嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그럼! 산통 깨는 녀석들은 난 질색이니까!","JPN":"もちろんだ！　計画を狂わせるやつらは許せないからな！","ENG":"Absolutely! Besides, I hate spoilsports!","TWN":"我最討厭那些搞砸別人事情的臭東西了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"나도 괜찮아. 교장 선생님께 학교 영상을 찍어 달라는 지시를 받았거든.","JPN":"私も大丈夫。校長先生から学校の映像を撮るようにと指示されたから。","ENG":"I'm okay, too. The Principal asked me to film this video for school.","TWN":"我也沒問題！正好我也收到了要幫校長拍校園影片的指示。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"교장 선생님께? 혹시 어제 받은 통신문과 관련 있나?","JPN":"校長先生に？　ひょっとして昨日もらったお便りと関係あるのか？","ENG":"The Principal? Does it have to do with his message yesterday?","TWN":"幫校長拍？這該不會和昨天收到的通知有關吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"맞아. 선도부의 활약을 남겨 두면 신입 선도부원들에게도 좋은 교육 자료로 쓸 수 있겠지?","JPN":"そうよ。風紀委員会の活躍を残しておけば、新入りの子たちの教育資料としても使えるでしょう？","ENG":"Yes. We can record your fighting and use it to teach new Council members.","TWN":"沒錯！如果能拍到先鋒部隊的活躍表現，這些影像對以後新進的先鋒成員來說，會是很好的教學資源吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그건 확실히...... 납득 가는 제안이군.","JPN":"それは確かに……納得のいく提案だな。","ENG":"That's... a tempting proposition.","TWN":"這確實是……不錯的提議。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"좋다. 카메라를 들고 따라와라.","JPN":"いいだろう。カメラを持ってついてこい。","ENG":"Alright, follow me with your camera.","TWN":"好吧，那妳拿著攝影機跟著過來吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"멋진 장면 부탁할게!","JPN":"最高のシーンを見せてちょうだい！","ENG":"Give me some good shots!","TWN":"要拍出帥氣的場面喔！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"레디, 액션!","JPN":"レディ、アクション！","ENG":"Ready... Action!","TWN":"準備——ACTION!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"반장...... 어째 반장도 평소보다 들떠 있지 않아?","JPN":"委員長……普段より浮かれてるのは気のせいか？","ENG":"Class President, why are you so excited?","TWN":"班長…咦？怎麼班長不像平時那樣活潑了?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};